import logo from "./FinTrack-Logo.png";
import "./Navbar.css";
import { NavLink } from "react-router-dom";
import { useState, useEffect } from "react";


function Navbar() {
  const [theme, setTheme] = useState("dark-purple");
      
  useEffect(() => {
      const savedTheme =
          localStorage.getItem("theme") || "dark-purple";

      setTheme(savedTheme);
  }, []);

  useEffect(() => {
      document.documentElement.setAttribute(
          "data-theme",
          theme
      );

      localStorage.setItem("theme", theme);
  }, [theme]);

  const toggleTheme = () => {
      setTheme(prev =>
          prev === "dark-purple"
              ? "lavender"
              : "dark-purple"
      );
  };
  return (
    <nav className="navbar">
      <div className="elements">

        <div className="logo">
          <img src={logo} alt="FinTrack Logo" className="logo" />
        </div>
        <div className="nav-right">
            <button
                className="btn-theme"
                id="themeToggle"
                onClick={toggleTheme}
            >
                {
                    theme === "dark-purple"
                        ? "✨ Light Mode"
                        : "🔮 Dark Mode"
                }
            </button>
        </div>
        <NavLink
          to="/dashboard"
          className={({ isActive }) =>
            isActive ? "nav-btn active" : "nav-btn"
          }
        >
          Dashboard
        </NavLink>

        <NavLink
          to="/transactions"
          className={({ isActive }) =>
            isActive ? "nav-btn active" : "nav-btn"
          }
        >
          Transactions
        </NavLink>

        <NavLink
          to="/analytics"
          className={({ isActive }) =>
            isActive ? "nav-btn active" : "nav-btn"
          }
        >
          Analytics
        </NavLink>

      </div>
    </nav>
  );
}

export default Navbar;
